diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index fdadf729fbd5..e75da8e4c7df 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7768,8 +7768,52 @@ static Instruction *foldFCmpReciprocalAndZero(FCmpInst &I, Instruction *LHSI,
 /// Optimize fabs(X) compared with zero.
 static Instruction *foldFabsWithFcmpZero(FCmpInst &I, InstCombinerImpl &IC) {
   Value *X;
-  if (!match(I.getOperand(0), m_FAbs(m_Value(X))))
+  if (match(I.getOperand(0), m_FAbs(m_Value(X)))) {
+    // fabs(X) pattern - continue with existing logic
+  } else if (auto *SI = dyn_cast<SelectInst>(I.getOperand(0))) {
+    // Try to match select pattern that computes fabs:
+    // (X >= 0) ? X : -X or (X < 0) ? -X : X -> fabs(X)
+    Value *CondVal = SI->getCondition();
+    Value *TrueVal = SI->getTrueValue();
+    Value *FalseVal = SI->getFalseValue();
+    FCmpInst::Predicate Pred;
+    Value *CmpOperand;
+    
+    // Check if condition is X cmp 0
+    if (!match(CondVal, m_FCmp(Pred, m_Value(CmpOperand), m_AnyZeroFP())))
+      return nullptr;
+    
+    // Check for (X >= 0) ? X : -X pattern
+    if ((Pred == FCmpInst::FCMP_OGE || Pred == FCmpInst::FCMP_UGE) &&
+        match(TrueVal, m_Specific(CmpOperand)) &&
+        match(FalseVal, m_FNeg(m_Specific(CmpOperand)))) {
+      X = CmpOperand;
+    }
+    // Check for (X > 0) ? X : -X pattern
+    else if ((Pred == FCmpInst::FCMP_OGT || Pred == FCmpInst::FCMP_UGT) &&
+             match(TrueVal, m_Specific(CmpOperand)) &&
+             match(FalseVal, m_FNeg(m_Specific(CmpOperand)))) {
+      X = CmpOperand;
+    }
+    // Check for (X < 0) ? -X : X pattern
+    else if ((Pred == FCmpInst::FCMP_OLT || Pred == FCmpInst::FCMP_ULT) &&
+             match(TrueVal, m_FNeg(m_Specific(CmpOperand))) &&
+             match(FalseVal, m_Specific(CmpOperand))) {
+      X = CmpOperand;
+    }
+    // Check for (X <= 0) ? -X : X pattern
+    else if ((Pred == FCmpInst::FCMP_OLE || Pred == FCmpInst::FCMP_ULE) &&
+             match(TrueVal, m_FNeg(m_Specific(CmpOperand))) &&
+             match(FalseVal, m_Specific(CmpOperand))) {
+      X = CmpOperand;
+    }
+    else {
+      return nullptr;
+    }
+  } else {
     return nullptr;
+  }
+

   const APFloat *C;
   if (!match(I.getOperand(1), m_APFloat(C)))

